SELECT CASHFLOW_BASE_ID, BATCH_EXECUTION_ID, CONTRACT_ID, CONTRACT_NO, INSTALLMENT_NO, PAYMENT_DATE,
       SCHEDULED_PAYMENT_AMT, SCHEDULED_PRINCIPAL_AMT, SCHEDULED_INTEREST_AMT
